// generated by sprint 61-1 — macOS entitlements plist generator

export interface EntitlementsOptions {
  readonly appSandbox: boolean;
  readonly networkClient: boolean;
  readonly networkServer: boolean;
  readonly fileAccessUserSelected: boolean;
  readonly fileAccessDownloads: boolean;
  readonly hardened: boolean;
}

const DEFAULT_ENTITLEMENTS: EntitlementsOptions = {
  appSandbox: false,
  networkClient: false,
  networkServer: false,
  fileAccessUserSelected: true,
  fileAccessDownloads: false,
  hardened: true,
};

export function generateEntitlementsPlist(
  options: Partial<EntitlementsOptions> = {}
): string {
  const opts: EntitlementsOptions = { ...DEFAULT_ENTITLEMENTS, ...options };

  const entries: string[] = [];

  if (opts.hardened) {
    entries.push(boolEntry("com.apple.security.cs.allow-unsigned-executable-memory", true));
    entries.push(boolEntry("com.apple.security.cs.allow-jit", true));
    entries.push(boolEntry("com.apple.security.cs.allow-dyld-environment-variables", false));
  }

  if (opts.appSandbox) {
    entries.push(boolEntry("com.apple.security.app-sandbox", true));
  }

  if (opts.networkClient) {
    entries.push(boolEntry("com.apple.security.network.client", true));
  }

  if (opts.networkServer) {
    entries.push(boolEntry("com.apple.security.network.server", true));
  }

  if (opts.fileAccessUserSelected) {
    entries.push(
      boolEntry("com.apple.security.files.user-selected.read-write", true)
    );
  }

  if (opts.fileAccessDownloads) {
    entries.push(
      boolEntry("com.apple.security.files.downloads.read-write", true)
    );
  }

  return `<?xml version="1.0" encoding="UTF-8"?>
<!DOCTYPE plist PUBLIC "-//Apple//DTD PLIST 1.0//EN" "http://www.apple.com/DTDs/PropertyList-1.0.dtd">
<plist version="1.0">
<dict>
${entries.join("\n")}
</dict>
</plist>
`;
}

function boolEntry(key: string, value: boolean): string {
  return `\t<key>${key}</key>\n\t<${value ? "true" : "false"}/>`;
}

export function generateInfoPlistOverrides(
  appName: string,
  version: string,
  minimumOsVersion: string,
  category: string
): Record<string, string> {
  return {
    CFBundleDisplayName: appName,
    CFBundleShortVersionString: version,
    CFBundleVersion: version,
    LSMinimumSystemVersion: minimumOsVersion,
    LSApplicationCategoryType: category,
    NSHighResolutionCapable: "true",
    NSSupportsAutomaticGraphicsSwitching: "true",
    CFBundleDocumentTypes: "",
  };
}
